const path = require('path');

const { NotificationType } = require('@prisma/client');

const prisma = require('../config/prisma');
const ApiError = require('../utils/ApiError');

const { logActivity } = require('./activityService');
const { createNotificationsBulk } = require('./notificationService');
const { ensureProjectAccess, syncProjectProgress } = require('./projectService');

const taskInclude = {
  assignee: {
    select: {
      id: true,
      name: true,
      email: true,
      avatar: true
    }
  },
  creator: {
    select: {
      id: true,
      name: true,
      email: true,
      avatar: true
    }
  },
  project: {
    select: {
      id: true,
      title: true,
      status: true,
      progress: true
    }
  },
  comments: {
    include: {
      author: {
        select: {
          id: true,
          name: true,
          avatar: true,
          role: true
        }
      }
    },
    orderBy: {
      createdAt: 'asc'
    }
  },
  attachments: {
    orderBy: {
      createdAt: 'desc'
    }
  }
};

function normalizeDueDate(dueDate) {
  return dueDate ? new Date(dueDate) : null;
}

function resolveTaskStatus(status, dueDate) {
  if (status === 'COMPLETED') {
    return 'COMPLETED';
  }

  if (dueDate && dueDate < new Date()) {
    return 'OVERDUE';
  }

  return status || 'TODO';
}

async function ensureTaskAccess(taskId, user) {
  const task = await prisma.task.findUnique({
    where: { id: taskId },
    include: {
      ...taskInclude,
      project: {
        include: {
          members: true
        }
      }
    }
  });

  if (!task) {
    throw new ApiError(404, 'Task not found');
  }

  const hasAccess =
    user.role === 'ADMIN' ||
    task.project.members.some((member) => member.userId === user.id) ||
    task.assignedToId === user.id;

  if (!hasAccess) {
    throw new ApiError(403, 'You do not have access to this task');
  }

  return task;
}

async function listTasks(user, query) {
  const page = Number(query.page || 1);
  const limit = Number(query.limit || 18);
  const skip = (page - 1) * limit;

  const where = {
    ...(query.projectId ? { projectId: query.projectId } : {}),
    ...(query.status ? { status: query.status } : {}),
    ...(query.priority ? { priority: query.priority } : {}),
    ...(query.assignedTo ? { assignedToId: query.assignedTo } : {}),
    ...(query.search
      ? {
          OR: [
            { title: { contains: query.search, mode: 'insensitive' } },
            { description: { contains: query.search, mode: 'insensitive' } }
          ]
        }
      : {}),
    ...(user.role === 'ADMIN'
      ? {}
      : {
          OR: [
            { assignedToId: user.id },
            {
              project: {
                members: {
                  some: { userId: user.id }
                }
              }
            }
          ]
        })
  };

  const sortBy = query.sortBy || 'updatedAt';
  const sortOrder = query.sortOrder || 'desc';

  const [items, total] = await Promise.all([
    prisma.task.findMany({
      where,
      include: taskInclude,
      orderBy: {
        [sortBy]: sortOrder
      },
      skip,
      take: limit
    }),
    prisma.task.count({ where })
  ]);

  return {
    items,
    meta: {
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit)
    }
  };
}

async function getTaskById(taskId, user) {
  return ensureTaskAccess(taskId, user);
}

async function createTask(payload, actor) {
  const project = await ensureProjectAccess(payload.projectId, actor);
  const dueDate = normalizeDueDate(payload.dueDate);
  const status = resolveTaskStatus(payload.status || 'TODO', dueDate);

  if (payload.assignedToId) {
    const membership = project.members.find((member) => member.userId === payload.assignedToId);
    if (!membership) {
      throw new ApiError(400, 'Assigned user must be a member of the project');
    }
  }

  const task = await prisma.task.create({
    data: {
      title: payload.title,
      description: payload.description || null,
      assignedToId: payload.assignedToId || null,
      projectId: payload.projectId,
      status,
      priority: payload.priority || 'MEDIUM',
      dueDate,
      createdById: actor.id,
      completedAt: status === 'COMPLETED' ? new Date() : null
    },
    include: taskInclude
  });

  await syncProjectProgress(task.projectId);
  await logActivity({
    actorId: actor.id,
    action: 'task.created',
    entityType: 'TASK',
    entityId: task.id,
    projectId: task.projectId,
    taskId: task.id,
    metadata: { title: task.title }
  });

  if (task.assignedToId) {
    await createNotificationsBulk([task.assignedToId], {
      title: 'Task assigned',
      message: `${task.title} was assigned to you`,
      type: NotificationType.TASK_ASSIGNED,
      entityId: task.id
    });
  }

  return task;
}

async function updateTask(taskId, payload, actor) {
  const existingTask = await ensureTaskAccess(taskId, actor);
  const dueDate = payload.dueDate !== undefined ? normalizeDueDate(payload.dueDate) : existingTask.dueDate;

  if (actor.role !== 'ADMIN' && existingTask.assignedToId !== actor.id) {
    throw new ApiError(403, 'Members can only update tasks assigned to them');
  }

  if (
    actor.role === 'ADMIN' &&
    payload.assignedToId &&
    !existingTask.project.members.some((member) => member.userId === payload.assignedToId)
  ) {
    throw new ApiError(400, 'Assigned user must be a member of the project');
  }

  const updateData =
    actor.role === 'ADMIN'
      ? {
          ...(payload.title ? { title: payload.title } : {}),
          ...(payload.description !== undefined ? { description: payload.description || null } : {}),
          ...(payload.assignedToId !== undefined
            ? { assignedToId: payload.assignedToId || null }
            : {}),
          ...(payload.priority ? { priority: payload.priority } : {}),
          ...(payload.dueDate !== undefined ? { dueDate } : {}),
          ...(payload.status ? { status: resolveTaskStatus(payload.status, dueDate) } : {})
        }
      : {
          ...(payload.status ? { status: resolveTaskStatus(payload.status, dueDate) } : {})
        };

  if (updateData.status === 'COMPLETED') {
    updateData.completedAt = new Date();
  } else if (updateData.status) {
    updateData.completedAt = null;
  }

  const task = await prisma.task.update({
    where: { id: taskId },
    data: updateData,
    include: taskInclude
  });

  await syncProjectProgress(task.projectId);
  await logActivity({
    actorId: actor.id,
    action: 'task.updated',
    entityType: 'TASK',
    entityId: task.id,
    projectId: task.projectId,
    taskId: task.id,
    metadata: {
      status: task.status,
      priority: task.priority
    }
  });

  const recipients = [task.assignedToId, task.createdById].filter((userId) => userId !== actor.id);
  if (recipients.length) {
    await createNotificationsBulk(recipients, {
      title: 'Task updated',
      message: `${task.title} was updated`,
      type: NotificationType.TASK_UPDATED,
      entityId: task.id
    });
  }

  return task;
}

async function deleteTask(taskId, actor) {
  const task = await ensureTaskAccess(taskId, actor);
  await logActivity({
    actorId: actor.id,
    action: 'task.deleted',
    entityType: 'TASK',
    entityId: taskId,
    metadata: { title: task.title }
  });

  await prisma.task.delete({
    where: { id: taskId }
  });

  await syncProjectProgress(task.projectId);
}

async function createComment(payload, actor) {
  const task = await ensureTaskAccess(payload.taskId, actor);

  const comment = await prisma.taskComment.create({
    data: {
      taskId: payload.taskId,
      authorId: actor.id,
      content: payload.content
    },
    include: {
      author: {
        select: {
          id: true,
          name: true,
          avatar: true,
          role: true
        }
      }
    }
  });

  await logActivity({
    actorId: actor.id,
    action: 'comment.created',
    entityType: 'COMMENT',
    entityId: comment.id,
    projectId: task.projectId,
    taskId: task.id,
    metadata: { taskTitle: task.title }
  });

  const recipients = [task.assignedToId, task.createdById].filter((userId) => userId && userId !== actor.id);
  if (recipients.length) {
    await createNotificationsBulk(recipients, {
      title: 'New task comment',
      message: `${actor.name} commented on ${task.title}`,
      type: NotificationType.COMMENT_ADDED,
      entityId: task.id
    });
  }

  return comment;
}

async function listComments(taskId, actor) {
  await ensureTaskAccess(taskId, actor);

  return prisma.taskComment.findMany({
    where: {
      taskId
    },
    include: {
      author: {
        select: {
          id: true,
          name: true,
          avatar: true,
          role: true
        }
      }
    },
    orderBy: {
      createdAt: 'asc'
    }
  });
}

async function addTaskAttachment(taskId, file, actor) {
  const task = await ensureTaskAccess(taskId, actor);

  if (actor.role !== 'ADMIN' && task.assignedToId !== actor.id) {
    throw new ApiError(403, 'Members can only upload files for their own tasks');
  }

  const attachment = await prisma.taskAttachment.create({
    data: {
      taskId,
      uploadedById: actor.id,
      filename: file.filename,
      originalName: file.originalname,
      url: `/uploads/${path.basename(file.path)}`,
      mimeType: file.mimetype,
      size: file.size
    }
  });

  await logActivity({
    actorId: actor.id,
    action: 'task.attachment_added',
    entityType: 'TASK',
    entityId: task.id,
    projectId: task.projectId,
    taskId: task.id,
    metadata: { filename: file.originalname }
  });

  return attachment;
}

module.exports = {
  addTaskAttachment,
  createComment,
  createTask,
  deleteTask,
  ensureTaskAccess,
  getTaskById,
  listComments,
  listTasks,
  updateTask
};
